int loxc_mod_demo_encode(const char *text, size_t text_len, loxc_writer_t *w) {
  if (text == NULL || w == NULL) return LOXC_ERR_NULL;
  size_t i = 0;
  while (i < text_len) {
    uint32_t sym_id = 0xFFFFFFFFu;
    size_t consumed = 1;
    for (uint32_t d = 0; d < (uint32_t)4071; d++) {
      size_t len = 0;
      const uint8_t *s = mod_demo_dict_entry(d, &len);
      if (len == 0) continue;
      if (i + len <= text_len && memcmp((const uint8_t *)text + i, s, len) == 0) {
        sym_id = mod_demo_dict_symbol_ids[d];
        consumed = len;
        break;
      }
    }
    if (sym_id == 0xFFFFFFFFu) {
      sym_id = mod_demo_byte_to_symbol[(uint8_t)text[i]];
      if (sym_id == 0xFFFFFFFFu) return LOXC_ERR_SYMBOL_NOT_FOUND;
      consumed = 1;
    }
    int rc = loxc_write_bits(w, sym_id, MOD_DEMO_SYMBOL_BITS);
    if (rc != LOXC_OK) return rc;
    i += consumed;
  }
  return LOXC_OK;
}

int loxc_mod_demo_decode(loxc_reader_t *r, char *out, size_t *inout_len) {
  if (r == NULL || out == NULL || inout_len == NULL) return LOXC_ERR_NULL;
  size_t cap = *inout_len;
  size_t pos = 0;
  while (!loxc_reader_eof(r)) {
    uint32_t sym_id = 0;
    int rc = loxc_read_bits(r, MOD_DEMO_SYMBOL_BITS, &sym_id);
    if (rc == LOXC_ERR_TRUNCATED) break;
    if (rc != LOXC_OK) return rc;
    if (sym_id >= 4167u) return LOXC_ERR_INVALID_FORMAT;
    const mod_demo_symbol_t s = mod_demo_symbols[sym_id];
    if (s.type == 0u) {
      if (pos + 1 > cap) return LOXC_ERR_OVERFLOW;
      out[pos++] = (char)(uint8_t)(s.byte_or_idx & 0xFFu);
    } else if (s.type == 1u) {
      const uint32_t di = s.byte_or_idx;
      if (di >= (uint32_t)4071u) return LOXC_ERR_INVALID_FORMAT;
      size_t len = 0;
      const uint8_t *ds = mod_demo_dict_entry(di, &len);
      if (pos + len > cap) return LOXC_ERR_OVERFLOW;
      memcpy(out + pos, ds, len);
      pos += len;
    } else {
      return LOXC_ERR_INVALID_FORMAT;
    }
  }
  *inout_len = pos;
  return LOXC_OK;
}

static const loxc_module_t mod_demo_module = {
  .name = "demo",
  .module_id = LOXC_MOD_DEMO_ID,
  .version = LOXC_MOD_DEMO_VERSION,
  .strategy_id = LOXC_MOD_DEMO_STRATEGY,
  .encode = mod_demo_encode_buffer,
  .decode = mod_demo_decode_buffer,
};

static int mod_demo_encode_buffer(const uint8_t *in, size_t in_len, uint8_t *out,
                                size_t out_cap, size_t *out_len) {
  if (out_len == NULL) return LOXC_ERR_NULL;
  *out_len = 0;
  if (in == NULL || out == NULL) return LOXC_ERR_NULL;
  if (in_len > 0xFFFFFFFFu) return LOXC_ERR_OVERFLOW;

  loxc_writer_t w;
  int rc = loxc_writer_init(&w, out, out_cap);
  if (rc != LOXC_OK) return rc;

  loxc_header_t h;
  h.module_id = LOXC_MOD_DEMO_ID;
  h.version = 2;
  h.flags = 0;
  h.strategy_id = (uint8_t)LOXC_MOD_DEMO_STRATEGY;
  h.data_len = 0;
  h.level_count = 0;
  for (int i = 0; i < 4; i++) h.reserved[i] = 0x00;
  h.crc32 = 0;

  rc = loxc_header_write(&w, &h);
  if (rc != LOXC_OK) return rc;

  rc = loxc_mod_demo_encode((const char *)in, in_len, &w);
  if (rc != LOXC_OK) return rc;
  rc = loxc_writer_flush(&w);
  if (rc != LOXC_OK) return rc;

  const size_t total = loxc_writer_size(&w);
  const size_t header_bytes = 15;
  if (total < header_bytes) return LOXC_ERR_INVALID_FORMAT;
  const size_t data_bytes = total - header_bytes;
  if (data_bytes > 0xFFFFu) return LOXC_ERR_OVERFLOW;
  out[7] = (uint8_t)(data_bytes & 0xFFu);
  out[8] = (uint8_t)((data_bytes >> 8) & 0xFFu);

  *out_len = total;
  return LOXC_OK;
}

static int mod_demo_decode_buffer(const uint8_t *in, size_t in_len, uint8_t *out,
                                size_t out_cap, size_t *out_len) {
  if (out_len == NULL) return LOXC_ERR_NULL;
  *out_len = 0;
  if (in == NULL || out == NULL) return LOXC_ERR_NULL;

  loxc_reader_t hr;
  int rc = loxc_reader_init(&hr, in, in_len);
  if (rc != LOXC_OK) return rc;

  loxc_header_t h;
  rc = loxc_header_read(&hr, &h);
  if (rc != LOXC_OK) return rc;
  if (h.module_id != LOXC_MOD_DEMO_ID) return LOXC_ERR_INVALID_MAGIC;
  if (h.version != 2) return LOXC_ERR_INVALID_MAGIC;
  if (h.flags != 0) return LOXC_ERR_INVALID_MAGIC;
  if (h.strategy_id != (uint8_t)LOXC_MOD_DEMO_STRATEGY) return LOXC_ERR_INVALID_MAGIC;

  const size_t header_bytes = 15;
  if (in_len < header_bytes) return LOXC_ERR_TRUNCATED;
  if ((size_t)h.data_len > (in_len - header_bytes)) return LOXC_ERR_TRUNCATED;

  loxc_reader_t r;
  rc = loxc_reader_init(&r, in + header_bytes, (size_t)h.data_len);
  if (rc != LOXC_OK) return rc;

  size_t cap = out_cap;
  rc = loxc_mod_demo_decode(&r, (char *)out, &cap);
  if (rc != LOXC_OK) return rc;
  *out_len = cap;
  return LOXC_OK;
}

int loxc_mod_demo_register(void) {
  return loxc_module_register(&mod_demo_module);
}
